  "description": "A futuristic, comprehensive global travel guide featuring AI-generated storytelling, detailed landmark information, and immersive visuals, centered around the theme of the Pyramids."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Landmark {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  category: 'History' | 'Nature' | 'Modern' | 'Hidden Gem';
  story?: string; // The "suspenseful story"
  visitorTips?: string[];
}

export interface Country {
  id: string;
  name: string; // Arabic name
  englishName: string;
  description: string;
  heroImage: string;
  landmarks: Landmark[];
  culturalTips: string[];
  bestTimeToVisit: string;
}

export interface GeminiResponse {
  landmarks: Landmark[];
  description: string;
  culturalTips: string[];
  bestTimeToVisit: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from '../types';

const apiKey = process.env.API_KEY || '';

// Initialize Gemini client
// Note: In a production app, handle the case where API_KEY is missing gracefully.
const ai = new GoogleGenAI({ apiKey });

export const getCountryDetails = async (countryName: string): Promise<GeminiResponse | null> => {
  if (!apiKey) {
    console.warn("No API Key provided for Gemini.");
    return null;
  }

  try {
    const model = 'gemini-3-flash-preview';

    const prompt = `
      You are an expert travel guide and historian for a futuristic travel website called "ALHARAM".
      Create a comprehensive travel guide for the country: "${countryName}".
      Language: Arabic.

      Requirements:
      1. "description": An engaging, professional introduction (2 sentences).
      2. "bestTimeToVisit": The ideal months to visit.
      3. "culturalTips": 3 key etiquette tips for tourists.
      4. "landmarks": List 4-6 specific famous landmarks or tourist attractions.
         For each landmark:
         - "name": Name in Arabic.
         - "id": a unique english slug.
         - "category": choose from 'History', 'Nature', 'Modern', 'Hidden Gem'.
         - "description": A factual brief description.
         - "story": A suspenseful, storytelling narrative about the place (2-3 sentences).
         - "visitorTips": 2 practical tips.
         - "imageUrl": use a keyword related to the place to be used in a search query (e.g. "Paris Eiffel Tower"). I will use this to map to a placeholder service later, just give me the keyword.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            bestTimeToVisit: { type: Type.STRING },
            culturalTips: { type: Type.ARRAY, items: { type: Type.STRING } },
            landmarks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  category: { type: Type.STRING, enum: ['History', 'Nature', 'Modern', 'Hidden Gem'] },
                  description: { type: Type.STRING },
                  story: { type: Type.STRING },
                  visitorTips: { type: Type.ARRAY, items: { type: Type.STRING } },
                  imageUrl: { type: Type.STRING }
                },
                required: ['id', 'name', 'category', 'description', 'story', 'visitorTips', 'imageUrl']
              }
            }
          },
          required: ['description', 'bestTimeToVisit', 'culturalTips', 'landmarks']
        }
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text) as GeminiResponse;
      // Map the keyword to a picsum-compatible URL or similar
      data.landmarks = data.landmarks.map(l => ({
        ...l,
        // Since we can't search picsum by keyword directly effectively in a static way without an extra API,
        // we will generate a deterministic random image from picsum to ensure it loads.
        // In a real app, we would use Unsplash API or Google Search API to get the real image URL.
        // For this demo, we mock it with a random seed based on ID.
        imageUrl: `https://picsum.photos/seed/${l.id}/800/600`
      }));
      return data;
    }
    return null;

  } catch (error) {
    console.error("Error fetching country details:", error);
    return null;
  }
};

