import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Country, GeminiResponse } from '../types';
import { STATIC_COUNTRIES } from '../constants';
import { getCountryDetails } from '../services/geminiService';
import LandmarkCard from '../components/LandmarkCard';
import { Calendar, Info, MapPin, AlertCircle, Loader2 } from 'lucide-react';

const CountryPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [data, setData] = useState<Country | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError(null);

      if (!id) return;

      // 1. Check Static Data first (case insensitive)
      const staticCountry = STATIC_COUNTRIES.find(
        c => c.id.toLowerCase() === id.toLowerCase() || 
             c.englishName.toLowerCase() === id.toLowerCase() || 
             c.name === id
      );

      if (staticCountry) {
        setData(staticCountry);
        setLoading(false);
        return;
      }

      // 2. Fetch from Gemini if not static
      try {
        const geminiData = await getCountryDetails(id);
        if (geminiData) {
          // Construct a Country object from Gemini response
          const newCountry: Country = {
            id: id,
            name: id, // Should ideally be Arabic name from Gemini, but using ID for now
            englishName: id,
            description: geminiData.description,
            heroImage: `https://picsum.photos/seed/${id}/1920/1080`, // Fallback hero
            bestTimeToVisit: geminiData.bestTimeToVisit,
            culturalTips: geminiData.culturalTips,
            landmarks: geminiData.landmarks
          };
          setData(newCountry);
        } else {
          setError("عذراً، لم نتمكن من جلب المعلومات لهذه الوجهة حالياً. يرجى المحاولة لاحقاً أو التأكد من الاسم.");
        }
      } catch (err) {
        setError("حدث خطأ أثناء الاتصال بالخادم الذكي.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-midnight text-white">
        <div className="relative">
          <div className="absolute inset-0 bg-gold-500/20 blur-xl rounded-full animate-pulse"></div>
          <Loader2 className="w-16 h-16 text-gold-500 animate-spin relative z-10" />
        </div>
        <h2 className="mt-8 text-2xl font-bold animate-pulse">جاري تحضير الدليل السياحي الذكي...</h2>
        <p className="text-gray-400 mt-2">نستجمع المعلومات ونكتب القصص لأجلك</p>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-midnight text-white pt-20">
        <AlertCircle className="w-20 h-20 text-red-500 mb-6" />
        <h2 className="text-3xl font-bold mb-4">عذراً</h2>
        <p className="text-gray-400 max-w-md text-center">{error || "وجهة غير معروفة"}</p>
        <button onClick={() => window.history.back()} className="mt-8 px-6 py-3 bg-white/10 hover:bg-white/20 rounded-full transition-colors">
          عودة للرئيسية
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-midnight pb-20">
      {/* Hero Header */}
      <div className="relative h-[60vh] w-full">
        <img src={data.heroImage} alt={data.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-b from-black/30 via-transparent to-midnight"></div>
        <div className="absolute bottom-0 left-0 right-0 p-8 md:p-16 max-w-7xl mx-auto">
          <div className="animate-fade-in-up">
            <h1 className="text-6xl md:text-8xl font-black text-white mb-4 drop-shadow-xl">{data.name}</h1>
            <p className="text-xl md:text-2xl text-gray-200 max-w-3xl leading-relaxed drop-shadow-md bg-black/30 p-4 rounded-xl backdrop-blur-sm">
              {data.description}
            </p>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-20 relative z-10">
        {/* Info Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-16">
          <div className="glass-panel p-6 rounded-2xl flex items-start gap-4">
            <div className="p-3 bg-gold-500/10 rounded-full text-gold-500">
              <Calendar size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-white mb-1">أفضل وقت للزيارة</h3>
              <p className="text-gray-300">{data.bestTimeToVisit}</p>
            </div>
          </div>

          <div className="glass-panel p-6 rounded-2xl flex items-start gap-4">
            <div className="p-3 bg-blue-500/10 rounded-full text-blue-400">
              <Info size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-white mb-1">نصائح ثقافية</h3>
              <ul className="text-gray-300 text-sm list-disc list-inside space-y-1">
                {data.culturalTips.map((tip, index) => (
                  <li key={index}>{tip}</li>
                ))}
              </ul>
            </div>
          </div>
        </div>

        {/* Landmarks Grid */}
        <h2 className="text-3xl font-bold text-white mb-8 border-r-4 border-gold-500 pr-4">أهم المعالم السياحية</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {data.landmarks.map((landmark) => (
            <LandmarkCard key={landmark.id} landmark={landmark} countryName={data.name} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default CountryPage;

import React from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import CountryPage from './pages/CountryPage';
import LandmarkPage from './pages/LandmarkPage';

// Scroll to top helper
const ScrollToTop = () => {
  const { pathname } = useLocation();

  React.useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

function App() {
  return (
    <Router>
      <ScrollToTop />
      <div className="flex flex-col min-h-screen bg-midnight text-white font-sans overflow-x-hidden">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/country/:id" element={<CountryPage />} />
            <Route path="/landmark/:id" element={<LandmarkPage />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
}

export default App;

