import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from '../types';

const apiKey = process.env.API_KEY || '';

// Initialize Gemini client
const ai = new GoogleGenAI({ apiKey });

export const getCountryDetails = async (countryName: string): Promise<GeminiResponse | null> => {
  if (!apiKey) {
    console.warn("No API Key provided for Gemini.");
    return null;
  }

  try {
    const model = 'gemini-3-flash-preview';

    // Updated prompt for more detailed and suspenseful storytelling
    const prompt = `
      You are an expert, world-class travel guide and storyteller for a futuristic travel website called "PYRAMID".
      Create a highly detailed, comprehensive travel guide for the country: "${countryName}".
      Language: Arabic.

      Requirements:
      1. "description": An engaging, professional, and inspiring introduction (3-4 sentences). Focus on what makes this country unique globally.
      2. "bestTimeToVisit": The ideal months to visit with a brief reason why.
      3. "culturalTips": 3-4 key cultural or etiquette tips for tourists to act like locals.
      4. "landmarks": List 5-6 top-tier famous landmarks or tourist attractions.
         For each landmark:
         - "name": Name in Arabic.
         - "id": a unique english slug.
         - "category": choose from 'History', 'Nature', 'Modern', 'Hidden Gem'.
         - "description": A detailed, factual description of the place (2 sentences).
         - "story": A suspenseful, immersive, and captivating story about the place (3-4 sentences). Use dramatic and descriptive language to transport the reader there. Mention legends, history, or the atmosphere.
         - "visitorTips": 2-3 practical, insider tips (e.g., best photo spot, hidden entrance, best time of day).
         - "imageUrl": use a keyword related to the place (e.g., "Rome Colosseum").
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            bestTimeToVisit: { type: Type.STRING },
            culturalTips: { type: Type.ARRAY, items: { type: Type.STRING } },
            landmarks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  category: { type: Type.STRING, enum: ['History', 'Nature', 'Modern', 'Hidden Gem'] },
                  description: { type: Type.STRING },
                  story: { type: Type.STRING },
                  visitorTips: { type: Type.ARRAY, items: { type: Type.STRING } },
                  imageUrl: { type: Type.STRING }
                },
                required: ['id', 'name', 'category', 'description', 'story', 'visitorTips', 'imageUrl']
              }
            }
          },
          required: ['description', 'bestTimeToVisit', 'culturalTips', 'landmarks']
        }
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text) as GeminiResponse;
      data.landmarks = data.landmarks.map(l => ({
        ...l,
        // Using seeded picsum images as we cannot generate real search URLs without a key.
        // The UI handles these elegantly.
        imageUrl: `https://picsum.photos/seed/${l.id}/800/600`
      }));
      return data;
    }
    return null;

  } catch (error) {
    console.error("Error fetching country details:", error);
    return null;
  }
};

import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Country } from '../types';
import { STATIC_COUNTRIES } from '../constants';
import { getCountryDetails } from '../services/geminiService';
import LandmarkCard from '../components/LandmarkCard';
import { Calendar, Info, MapPin, AlertCircle, Loader2, Lightbulb, Share2, Heart } from 'lucide-react';

const CountryPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [data, setData] = useState<Country | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError(null);

      if (!id) return;

      // 1. Check Static Data first (case insensitive)
      const staticCountry = STATIC_COUNTRIES.find(
        c => c.id.toLowerCase() === id.toLowerCase() || 
             c.englishName.toLowerCase() === id.toLowerCase() || 
             c.name === id
      );

      if (staticCountry) {
        setData(staticCountry);
        setLoading(false);
        return;
      }

      // 2. Fetch from Gemini if not static
      try {
        const geminiData = await getCountryDetails(id);
        if (geminiData) {
          // Construct a Country object from Gemini response
          const newCountry: Country = {
            id: id,
            name: id, 
            englishName: id,
            description: geminiData.description,
            heroImage: `https://picsum.photos/seed/${id}/1920/1080`,
            bestTimeToVisit: geminiData.bestTimeToVisit,
            culturalTips: geminiData.culturalTips,
            landmarks: geminiData.landmarks
          };
          setData(newCountry);
        } else {
          setError("عذراً، لم نتمكن من جلب المعلومات لهذه الوجهة حالياً. يرجى المحاولة لاحقاً أو التأكد من الاسم.");
        }
      } catch (err) {
        setError("حدث خطأ أثناء الاتصال بالخادم الذكي.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-midnight text-white">
        <div className="relative">
          <div className="absolute inset-0 bg-gold-500/20 blur-xl rounded-full animate-pulse"></div>
          <Loader2 className="w-16 h-16 text-gold-500 animate-spin relative z-10" />
        </div>
        <h2 className="mt-8 text-2xl font-bold animate-pulse">جاري تحضير الدليل السياحي الذكي...</h2>
        <p className="text-gray-400 mt-2">نستجمع المعلومات ونكتب القصص لأجلك</p>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-midnight text-white pt-20">
        <AlertCircle className="w-20 h-20 text-red-500 mb-6" />
        <h2 className="text-3xl font-bold mb-4">عذراً</h2>
        <p className="text-gray-400 max-w-md text-center">{error || "وجهة غير معروفة"}</p>
        <button onClick={() => window.history.back()} className="mt-8 px-6 py-3 bg-white/10 hover:bg-white/20 rounded-full transition-colors">
          عودة للرئيسية
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-midnight pb-20">
      {/* Hero Header */}
      <div className="relative h-[50vh] w-full shadow-2xl shadow-black/50">
        <img src={data.heroImage} alt={data.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-b from-black/40 via-transparent to-midnight"></div>
        <div className="absolute bottom-0 left-0 right-0 p-8 md:p-12 max-w-7xl mx-auto">
          <div className="animate-fade-in-up">
            <h1 className="text-5xl md:text-7xl font-black text-white mb-2 drop-shadow-xl border-r-8 border-gold-500 pr-6">{data.name}</h1>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

          {/* Sidebar Section (1 Column) */}
          <div className="lg:col-span-1 space-y-6">
             {/* Description Mini-Card */}
             <div className="glass-panel p-6 rounded-2xl">
                <h3 className="text-lg font-bold text-white mb-3 flex items-center gap-2">
                  <Info size={20} className="text-gold-500"/> عن الوجهة
                </h3>
                <p className="text-gray-400 text-sm leading-relaxed">
                  {data.description}
                </p>
             </div>

            {/* Best Time Card */}
            <div className="glass-panel p-6 rounded-2xl border-t-4 border-gold-500 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                <Calendar size={80} />
              </div>
              <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2 relative z-10">
                <Calendar className="text-gold-500" size={20} /> أفضل وقت للزيارة
              </h3>
              <p className="text-gray-300 leading-relaxed relative z-10 font-medium">
                {data.bestTimeToVisit}
              </p>
            </div>

            {/* Traveler Tips Card */}
            <div className="glass-panel p-6 rounded-2xl border-t-4 border-blue-500 relative overflow-hidden">
               <div className="absolute -bottom-4 -left-4 p-4 opacity-5">
