              <p className="text-gray-400">استكشف أهم الأماكن التي يوصى بزيارتها في {data.name}</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {data.landmarks.map((landmark) => (
