import React, { useState, useEffect } from 'react';
import { Volume2, Square, Radio } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  text: string;
}

const AudioPlayer: React.FC<Props> = ({ text }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isSupported, setIsSupported] = useState(false);
  const { language, t } = useLanguage();
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    if ('speechSynthesis' in window) {
      setIsSupported(true);

      const loadVoices = () => {
        const availableVoices = window.speechSynthesis.getVoices();
        setVoices(availableVoices);
      };

      loadVoices();
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handlePlay = () => {
    if (!isSupported) return;

    window.speechSynthesis.cancel();

    const newUtterance = new SpeechSynthesisUtterance(text);

    // Select the best "Historical/Radio" voice
    let selectedVoice = null;

    // Filter based on current language
    const langVoices = voices.filter(v => v.lang.startsWith(language));

    // Try to find a male voice or specific keywords often associated with deeper voices
    if (language === 'en') {
        selectedVoice = langVoices.find(v => v.name.includes('Google US English') || v.name.includes('Male')) || langVoices[0];
    } else if (language === 'ar') {
        selectedVoice = langVoices.find(v => v.name.includes('Maged') || v.name.includes('Male')) || langVoices[0];
    } else {
        selectedVoice = langVoices.find(v => v.name.includes('Male')) || langVoices[0];
    }

    if (selectedVoice) {
        newUtterance.voice = selectedVoice;
    }

    newUtterance.lang = language === 'ar' ? 'ar-SA' : 'en-US';

    // THE "HISTORICAL RADIO" EFFECT SETTINGS
    // Slower rate for gravity and storytelling
    newUtterance.rate = 0.85; 
    // Lower pitch for a deeper, more authoritative male voice
    newUtterance.pitch = 0.7; 
    // Volume full
    newUtterance.volume = 1.0;

    newUtterance.onend = () => setIsPlaying(false);
    newUtterance.onerror = () => setIsPlaying(false);

    window.speechSynthesis.speak(newUtterance);
    setIsPlaying(true);
  };

  const handleStop = () => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
  };

  if (!isSupported) return null;

  return (
    <button
      onClick={isPlaying ? handleStop : handlePlay}
      className={`
        flex items-center gap-2 px-5 py-2.5 rounded-full font-bold text-sm transition-all duration-500 shadow-lg
        ${isPlaying 
          ? 'bg-red-500/10 text-red-400 border border-red-500/50 hover:bg-red-500/20' 
          : 'bg-gradient-to-r from-gold-600 to-amber-700 text-black border border-gold-400/50 hover:scale-105 hover:shadow-gold-500/20'
        }
      `}
    >
      {isPlaying ? (
        <>
          <span className="relative flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
          </span>
          <Square size={16} fill="currentColor" />
          {t('stopStory')}
        </>
      ) : (
        <>
          <Radio size={18} />
          {t('listenStory')}
        </>
      )}
    </button>
  );
};

export default AudioPlayer;

import React, { useState, useEffect, useRef } from 'react';
import { Volume2, VolumeX, Wind, Waves, Building2 } from 'lucide-react';

interface Props {
  category: 'History' | 'Nature' | 'Modern' | 'Hidden Gem';
}

// Using high-quality, royalty-free loops
const SOUNDS = {
  History: 'https://cdn.pixabay.com/download/audio/2022/03/24/audio_893279e869.mp3?filename=desert-wind-19349.mp3', // Desert Wind / Ethereal
  Nature: 'https://cdn.pixabay.com/download/audio/2021/08/09/audio_00839845a7.mp3?filename=ocean-waves-112906.mp3', // Ocean/Nature
  Modern: 'https://cdn.pixabay.com/download/audio/2021/09/06/audio_2e22896564.mp3?filename=city-ambience-11502.mp3', // City Ambience
  'Hidden Gem': 'https://cdn.pixabay.com/download/audio/2022/02/07/audio_6e5229c29d.mp3?filename=birds-in-forest-20703.mp3' // Birds/Calm
};

const AmbientSound: React.FC<Props> = ({ category }) => {
  const [isMuted, setIsMuted] = useState(false); // Start unmuted for immersion, or true if preferred
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Auto-play with low volume when component mounts
    if (audioRef.current) {
      audioRef.current.volume = 0.2; // Keep it subtle background noise
      audioRef.current.play().catch(e => {
        // Autoplay policies might block this without user interaction
        setIsMuted(true);
      });
    }

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
      }
    };
  }, [category]);

  const toggleMute = () => {
    if (audioRef.current) {
      audioRef.current.muted = !isMuted;
      if (isMuted) audioRef.current.play().catch(() => {});
      setIsMuted(!isMuted);
    }
  };

  const getIcon = () => {
    if (isMuted) return <VolumeX size={20} />;
    switch(category) {
        case 'History': return <Wind size={20} className="animate-pulse" />;
        case 'Nature': 
        case 'Hidden Gem': return <Waves size={20} className="animate-pulse" />;
        case 'Modern': return <Building2 size={20} className="animate-pulse" />;
        default: return <Volume2 size={20} />;
    }
  };

  return (
    <div className="fixed top-24 left-6 z-40 hidden md:block">
      <audio 
        ref={audioRef} 
        src={SOUNDS[category] || SOUNDS.History} 
        loop 
        muted={isMuted}
      />
      <button 
        onClick={toggleMute}
        className={`
            flex items-center gap-3 px-4 py-3 rounded-full backdrop-blur-md border transition-all duration-500
            ${isMuted 
                ? 'bg-black/30 text-gray-400 border-white/10' 
                : 'bg-gold-500/20 text-gold-500 border-gold-500/50 shadow-lg shadow-gold-500/10'}
        `}
        title={isMuted ? "Unmute Atmosphere" : "Mute Atmosphere"}
      >
        {getIcon()}
        <span className={`text-xs font-bold uppercase tracking-widest transition-all duration-300 ${isMuted ? 'w-0 opacity-0 overflow-hidden' : 'w-auto opacity-100'}`}>
            Atmosphere
        </span>
      </button>
    </div>
  );
};

export default AmbientSound;

