import React, { useState, useEffect, useRef } from 'react';
import { Volume2, VolumeX, Wind, Waves, Building2, TreePine } from 'lucide-react';

interface Props {
  category: 'History' | 'Nature' | 'Modern' | 'Hidden Gem';
}

// Reliable, high-quality audio sources from Google Sounds
const SOUNDS = {
  // Desert wind for historical sites
  History: 'https://actions.google.com/sounds/v1/weather/desert_sand_drift.ogg',
  // Ocean waves/Nature
  Nature: 'https://actions.google.com/sounds/v1/water/waves_crashing_on_rock_beach.ogg',
  // General calm nature for hidden gems
  'Hidden Gem': 'https://actions.google.com/sounds/v1/animals/birds_forest_morning.ogg',
  // City ambience/traffic for modern
  Modern: 'https://actions.google.com/sounds/v1/ambiences/coffee_shop.ogg'
};

const AmbientSound: React.FC<Props> = ({ category }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const audio = audioRef.current;
    if (audio) {
      audio.volume = 0.3; // Gentle background volume

      // Attempt auto-play
      const playPromise = audio.play();

      if (playPromise !== undefined) {
        playPromise
          .then(() => {
            setIsPlaying(true);
            setIsMuted(false);
          })
          .catch((error) => {
            // Auto-play was prevented by the browser
            console.log("Autoplay prevented:", error);
            setIsPlaying(false);
            setIsMuted(true);
          });
      }
    }

    return () => {
      if (audio) {
        audio.pause();
      }
    };
  }, [category]);

  const toggleMute = () => {
    if (audioRef.current) {
      if (isMuted) {
        // Unmute and play
        audioRef.current.muted = false;
        audioRef.current.play().then(() => setIsPlaying(true));
        setIsMuted(false);
      } else {
        // Mute
        audioRef.current.muted = true;
        setIsMuted(true);
        setIsPlaying(false);
      }
    }
  };

  const getIcon = () => {
    if (isMuted) return <VolumeX size={20} />;
    switch(category) {
        case 'History': return <Wind size={20} className="text-amber-400" />;
        case 'Nature': return <Waves size={20} className="text-blue-400" />;
        case 'Hidden Gem': return <TreePine size={20} className="text-green-400" />;
        case 'Modern': return <Building2 size={20} className="text-purple-400" />;
        default: return <Volume2 size={20} />;
    }
  };

  return (
    <div className="fixed top-24 left-6 z-40 hidden md:flex items-center gap-3">
      <audio 
        ref={audioRef} 
        src={SOUNDS[category] || SOUNDS.History} 
        loop 
        crossOrigin="anonymous"
      />

      {/* Visual Equalizer Bars (Only animate when playing) */}
      <div className={`flex items-end gap-1 h-8 ${!isPlaying ? 'opacity-0' : 'opacity-100'} transition-opacity duration-500`}>
        <div className="w-1 bg-gold-500 animate-[bounce_1s_infinite] h-3"></div>
        <div className="w-1 bg-gold-500 animate-[bounce_1.2s_infinite] h-6"></div>
        <div className="w-1 bg-gold-500 animate-[bounce_0.8s_infinite] h-4"></div>
        <div className="w-1 bg-gold-500 animate-[bounce_1.5s_infinite] h-7"></div>
      </div>

      <button 
        onClick={toggleMute}
        className={`
            relative overflow-hidden flex items-center gap-3 px-5 py-3 rounded-full backdrop-blur-xl border transition-all duration-300 group
            ${isMuted 
                ? 'bg-black/40 text-gray-400 border-white/10 hover:border-white/30' 
                : 'bg-gold-500/10 text-white border-gold-500/50 shadow-[0_0_15px_rgba(234,179,8,0.2)]'}
        `}
      >
        <div className="relative z-10 flex items-center gap-2">
            {getIcon()}
            <span className={`text-xs font-bold uppercase tracking-widest ${isMuted ? 'text-gray-500' : 'text-gold-500'}`}>
                {isMuted ? "Sound Off" : "Atmosphere"}
            </span>
        </div>

        {/* Button Hover Glow */}
        {!isMuted && (
            <div className="absolute inset-0 bg-gold-500/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        )}
      </button>
    </div>
  );
};

export default AmbientSound;

